1116→+/**
1117→+ * Error classifier — categorizes phase failures from stderr content.
1118→+ *
1119→+ * Pattern-matches stderr lines against known error signatures to produce
1120→+ * a structured category for analytics and debugging.
1121→+ */
1122→+
1123→+/** All recognized error categories (AC-7: defined as constants). */
1124→+export const ERROR_CATEGORIES = [
1125→+  "context_overflow",
1126→+  "api_error",
1127→+  "hook_failure",
1128→+  "build_error",
1129→+  "timeout",
1130→+  "unknown",
1131→+] as const;
1132→+
1133→+export type ErrorCategory = (typeof ERROR_CATEGORIES)[number];
1134→+
1135→+/**
1136→+ * Ordered list of classifiers. First match wins (highest priority first).
1137→+ */
1138→+const CLASSIFIERS: { category: ErrorCategory; patterns: RegExp[] }[] = [
1139→+  {
1140→+    category: "context_overflow",
1141→+    patterns: [
1142→+      /context window/i,
1143→+      /token limit/i,
1144→+      /context length/i,
1145→+      /max.?context/i,
1146→+      /exceeded.*context/i,
1147→+    ],
1148→+  },
1149→+  {
1150→+    category: "timeout",
1151→+    patterns: [/timeout/i, /timed?\s*out/i, /SIGTERM/, /deadline exceeded/i],
1152→+  },
1153→+  {
1154→+    category: "api_error",
1155→+    patterns: [
1156→+      /rate.?limit/i,
1157→+      /429/,
1158→+      /api.*error/i,
1159→+      /auth.*fail/i,
1160→+      /unauthorized/i,
1161→+      /503/,
1162→+      /502/,
1163→+      /overloaded/i,
1164→+    ],
1165→+  },
1166→+  {
1167→+    category: "hook_failure",
1168→+    patterns: [
1169→+      /hook.*fail/i,
1170→+      /pre-?commit/i,
1171→+      /HOOK_BLOCKED/i,
1172→+      /blocked by hook/i,
1173→+    ],
1174→+  },
1175→+  {
1176→+    category: "build_error",
1177→+    patterns: [
1178→+      /typescript.*error/i,
1179→+      /TS\d{4,5}:/,
1180→+      /syntax\s*error/i,
1181→+      /cannot find module/i,
1182→+      /compilation.*fail/i,
1183→+      /build.*fail/i,
1184→+      /eslint/i,
1185→+      /npm ERR!/,
1186→+    ],
1187→+  },
1188→+];
1189→+
1190→+/**
1191→+ * Classify stderr lines into an error category.
1192→+ *
1193→+ * Scans lines in order; the first classifier whose pattern matches any line wins.
1194→+ * Returns "unknown" if no patterns match.
1195→+ */
1196→+export function classifyError(stderrLines: string[]): ErrorCategory {
1197→+  if (!stderrLines || stderrLines.length === 0) {
1198→+    return "unknown";
1199→+  }
1200→+
1201→+  for (const { category, patterns } of CLASSIFIERS) {
1202→+    for (const line of stderrLines) {
1203→+      for (const pattern of patterns) {
1204→+        if (pattern.test(line)) {
1205→+          return category;
1206→+        }
1207→+      }
1208→+    }
1209→+  }
1210→+
1211→+  return "unknown";
1212→+}
