1278→@@ -0,0 +1,40 @@
1279→+/**
1280→+ * RingBuffer — fixed-capacity circular buffer for retaining the last N lines.
1281→+ *
1282→+ * Used by agent drivers to capture the tail of stderr/stdout without
1283→+ * unbounded memory growth.
1284→+ */
1285→+
1286→+export class RingBuffer {
1287→+  private buffer: string[];
1288→+  private head = 0;
1289→+  private count = 0;
1290→+  private readonly capacity: number;
1291→+
1292→+  constructor(capacity: number) {
1293→+    this.capacity = capacity;
1294→+    this.buffer = new Array<string>(capacity);
1295→+  }
1296→+
1297→+  /** Push a line into the buffer, evicting the oldest if at capacity. */
1298→+  push(line: string): void {
1299→+    this.buffer[this.head] = line;
1300→+    this.head = (this.head + 1) % this.capacity;
1301→+    if (this.count < this.capacity) {
1302→+      this.count++;
1303→+    }
1304→+  }
1305→+
1306→+  /** Return the stored lines in insertion order (oldest first). */
1307→+  getLines(): string[] {
1308→+    if (this.count === 0) return [];
1309→+    if (this.count < this.capacity) {
1310→+      return this.buffer.slice(0, this.count);
1311→+    }
1312→+    // Buffer is full — head points to the oldest entry
1313→+    return [
1314→+      ...this.buffer.slice(this.head),
1315→+      ...this.buffer.slice(0, this.head),
1316→+    ];
1317→+  }
1318→+}
