/**
 * RingBuffer — fixed-capacity circular buffer for retaining the last N lines.
 *
 * Used by agent drivers to capture the tail of stderr/stdout without
 * unbounded memory growth.
 */

export class RingBuffer {
  private buffer: string[];
  private head = 0;
  private count = 0;
  private readonly capacity: number;

  constructor(capacity: number) {
    this.capacity = capacity;
    this.buffer = new Array<string>(capacity);
  }

  /** Push a line into the buffer, evicting the oldest if at capacity. */
  push(line: string): void {
    this.buffer[this.head] = line;
    this.head = (this.head + 1) % this.capacity;
    if (this.count < this.capacity) {
      this.count++;
    }
  }

  /** Return the stored lines in insertion order (oldest first). */
  getLines(): string[] {
    if (this.count === 0) return [];
    if (this.count < this.capacity) {
      return this.buffer.slice(0, this.count);
    }
    // Buffer is full — head points to the oldest entry
    return [
      ...this.buffer.slice(this.head),
      ...this.buffer.slice(0, this.head),
    ];
  }
}

/**
 * Error classifier — categorizes phase failures from stderr content.
 *
 * Pattern-matches stderr lines against known error signatures to produce
 * a structured category for analytics and debugging.
 */

/** All recognized error categories (AC-7: defined as constants). */
export const ERROR_CATEGORIES = [
  "context_overflow",
  "api_error",
  "hook_failure",
  "build_error",
  "timeout",
  "unknown",
] as const;

export type ErrorCategory = (typeof ERROR_CATEGORIES)[number];

/**
 * Ordered list of classifiers. First match wins (highest priority first).
 */
const CLASSIFIERS: { category: ErrorCategory; patterns: RegExp[] }[] = [
  {
    category: "context_overflow",
    patterns: [
      /context window/i,
      /token limit/i,
      /context length/i,
      /max.?context/i,
      /exceeded.*context/i,
    ],
  },
  {
    category: "timeout",
    patterns: [/timeout/i, /timed?\s*out/i, /SIGTERM/, /deadline exceeded/i],
  },
  {
    category: "api_error",
    patterns: [
      /rate.?limit/i,
      /429/,
      /api.*error/i,
      /auth.*fail/i,
      /unauthorized/i,
      /503/,
      /502/,
      /overloaded/i,
    ],
  },
  {
    category: "hook_failure",
    patterns: [
      /hook.*fail/i,
      /pre-?commit/i,
      /HOOK_BLOCKED/i,
      /blocked by hook/i,
    ],
  },
  {
    category: "build_error",
    patterns: [
      /typescript.*error/i,
      /TS\d{4,5}:/,
      /syntax\s*error/i,
      /cannot find module/i,
      /compilation.*fail/i,
      /build.*fail/i,
      /eslint/i,
      /npm ERR!/,
    ],
  },
];

/**
 * Classify stderr lines into an error category.
 *
 * Scans lines in order; the first classifier whose pattern matches any line wins.
 * Returns "unknown" if no patterns match.
 */
export function classifyError(stderrLines: string[]): ErrorCategory {
  if (!stderrLines || stderrLines.length === 0) {
    return "unknown";
  }

  for (const { category, patterns } of CLASSIFIERS) {
    for (const line of stderrLines) {
      for (const pattern of patterns) {
        if (pattern.test(line)) {
          return category;
        }
      }
    }
  }

  return "unknown";
}

export type CacheMetrics = z.infer<typeof CacheMetricsSchema>;

/**
 * Structured error context captured from phase failures (#447).
 *
 * Provides stderr/stdout tails and a categorized error type
 * for better failure diagnostics and analytics.
 */
export const ErrorContextSchema = z.object({
  /** Last N lines of stderr before process exit */
  stderrTail: z.array(z.string()),
  /** Last N lines of stdout before process exit */
  stdoutTail: z.array(z.string()),
  /** Process exit code */
  exitCode: z.number().int().optional(),
  /** Classified error category */
  category: z.enum([
    "context_overflow",
    "api_error",
    "hook_failure",
    "build_error",
    "timeout",
    "unknown",
  ]),
});

export type ErrorContext = z.infer<typeof ErrorContextSchema>;

/**
 * Log entry for a single phase execution
 */
export const PhaseLogSchema = z.object({
  /** Phase that was executed */
  phase: PhaseSchema,
  /** GitHub issue number */
  issueNumber: z.number().int().positive(),
  /** When the phase started */
  startTime: z.string().datetime(),
  /** When the phase ended */
  endTime: z.string().datetime(),
  /** Duration in seconds */
  durationSeconds: z.number().nonnegative(),
  /** Execution result */
  status: PhaseStatusSchema,
  /** Error message if failed */
  error: z.string().optional(),
  /** Number of iterations (for loop phase) */
  iterations: z.number().int().nonnegative().optional(),
  /** Files modified during this phase */
  filesModified: z.array(z.string()).optional(),
  /** Number of tests run (for test/qa phases) */
  testsRun: z.number().int().nonnegative().optional(),
  /** Number of tests passed */
  testsPassed: z.number().int().nonnegative().optional(),
  /** Parsed QA verdict (only for qa phase) */
  verdict: QaVerdictSchema.optional(),
  /** Git commit SHA after phase completes (AC-2) */
  commitHash: z.string().optional(),
  /** Per-file diff statistics (AC-3) */
  fileDiffStats: z.array(FileDiffStatSchema).optional(),
  /** Cache metrics for QA phase (AC-7) */
  cacheMetrics: CacheMetricsSchema.optional(),
  /** Structured error context for failed phases (#447) */
  errorContext: ErrorContextSchema.optional(),
});

export type PhaseLog = z.infer<typeof PhaseLogSchema>;

/**
 * Complete execution record for a single issue
 */
export const IssueLogSchema = z.object({
  /** GitHub issue number */
  issueNumber: z.number().int().positive(),
