  1→/**
  2→ * ClaudeCodeDriver — AgentDriver implementation wrapping the Claude Agent SDK.
  3→ *
  4→ * Owns the `@anthropic-ai/claude-agent-sdk` import. No other file in the
  5→ * orchestration layer should import the SDK directly.
  6→ */
  7→
  8→import { query } from "@anthropic-ai/claude-agent-sdk";
  9→import type { SDKResultMessage } from "@anthropic-ai/claude-agent-sdk";
 10→import { getMcpServersConfig } from "../../system.js";
 11→import { RingBuffer } from "../ring-buffer.js";
 12→import type {
 13→  AgentDriver,
 14→  AgentExecutionConfig,
 15→  AgentPhaseResult,
 16→} from "./agent-driver.js";
 17→
 18→export class ClaudeCodeDriver implements AgentDriver {
 19→  name = "claude-code";
 20→
 21→  /**
 22→   * Track session ID across calls so callers can implement resume.
 23→   * Set after each executePhase() call.
 24→   */
 25→  private lastSessionId?: string;
 26→
 27→  async executePhase(
 28→    prompt: string,
 29→    config: AgentExecutionConfig,
 30→  ): Promise<AgentPhaseResult> {
 31→    const abortController = new AbortController();
 32→
 33→    // Wire external abort signal
 34→    if (config.abortSignal) {
 35→      config.abortSignal.addEventListener("abort", () =>
 36→        abortController.abort(),
 37→      );
 38→    }
 39→
 40→    // Set up timeout
 41→    const timeoutId = setTimeout(() => {
 42→      abortController.abort();
 43→    }, config.phaseTimeout * 1000);
 44→
 45→    let resultSessionId: string | undefined;
 46→    let resultMessage: SDKResultMessage | undefined;
 47→    let capturedOutput = "";
 48→    let capturedStderr = "";
 49→    const stderrBuffer = new RingBuffer(50);
 50→    const stdoutBuffer = new RingBuffer(50);
 51→
 52→    try {
 53→      // Get MCP servers config if enabled
 54→      const mcpServers = config.mcp ? getMcpServersConfig() : undefined;
 55→
 56→      const queryInstance = query({
 57→        prompt,
 58→        options: {
 59→          abortController,
 60→          cwd: config.cwd,
 61→          settingSources: ["project"],
 62→          systemPrompt: { type: "preset", preset: "claude_code" },
 63→          tools: { type: "preset", preset: "claude_code" },
 64→          permissionMode: "bypassPermissions",
 65→          allowDangerouslySkipPermissions: true,
 66→          // Resume from previous session if provided
 67→          ...(config.sessionId ? { resume: config.sessionId } : {}),
 68→          env: config.env,
 69→          ...(mcpServers ? { mcpServers } : {}),
 70→          stderr: (data: string) => {
 71→            capturedStderr += data;
 72→            // Split on newlines and push each line to the ring buffer
 73→            const lines = data.split("\n").filter((l) => l.length > 0);
 74→            for (const line of lines) {
 75→              stderrBuffer.push(line);
 76→            }
 77→            config.onStderr?.(data);
 78→          },
 79→        },
 80→      });
 81→
 82→      // Stream and process messages
 83→      for await (const message of queryInstance) {
 84→        if (message.type === "system" && message.subtype === "init") {
 85→          resultSessionId = message.session_id;
 86→        }
 87→
 88→        if (message.type === "assistant") {
 89→          const content = message.message.content as Array<{
 90→            type: string;
 91→            text?: string;
 92→          }>;
 93→          const textContent = content
 94→            .filter((c) => c.type === "text" && c.text)
 95→            .map((c) => c.text)
 96→            .join("");
 97→          if (textContent) {
 98→            capturedOutput += textContent;
 99→            const lines = textContent.split("\n").filter((l) => l.length > 0);
100→            for (const line of lines) {
101→              stdoutBuffer.push(line);
102→            }
103→            config.onOutput?.(textContent);
104→          }
105→        }
106→
107→        if (message.type === "result") {
108→          resultMessage = message;
109→        }
110→      }
111→
112→      clearTimeout(timeoutId);
113→      this.lastSessionId = resultSessionId;
114→
115→      if (resultMessage) {
116→        if (resultMessage.subtype === "success") {
117→          return {
118→            success: true,
119→            output: capturedOutput,
120→            sessionId: resultSessionId,
121→            stderrTail: stderrBuffer.getLines(),
122→            stdoutTail: stdoutBuffer.getLines(),
123→          };
124→        }
125→
126→        // Handle error subtypes
127→        let error: string;
128→        const errorSubtype = resultMessage.subtype;
129→        if (errorSubtype === "error_max_turns") {
130→          error = "Max turns reached";
131→        } else if (errorSubtype === "error_during_execution") {
132→          error = resultMessage.errors?.join(", ") || "Error during execution";
133→        } else if (errorSubtype === "error_max_budget_usd") {
134→          error = "Budget limit exceeded";
135→        } else {
136→          error = `Error: ${errorSubtype}`;
137→        }
138→
139→        return {
140→          success: false,
141→          output: capturedOutput,
142→          sessionId: resultSessionId,
143→          error,
144→          stderrTail: stderrBuffer.getLines(),
145→          stdoutTail: stdoutBuffer.getLines(),
146→        };
147→      }
148→
149→      return {
150→        success: false,
151→        output: capturedOutput,
152→        sessionId: resultSessionId,
153→        error: "No result received from Claude",
154→        stderrTail: stderrBuffer.getLines(),
155→        stdoutTail: stdoutBuffer.getLines(),
156→      };
157→    } catch (err) {
158→      clearTimeout(timeoutId);
159→      const error = err instanceof Error ? err.message : String(err);
160→
161→      if (error.includes("abort") || error.includes("AbortError")) {
162→        return {
163→          success: false,
164→          output: capturedOutput,
165→          error: `Timeout after ${config.phaseTimeout}s`,
166→          stderrTail: stderrBuffer.getLines(),
167→          stdoutTail: stdoutBuffer.getLines(),
168→        };
169→      }
170→
171→      const stderrSuffix = capturedStderr
172→        ? `\nStderr: ${capturedStderr.slice(0, 500)}`
173→        : "";
174→
175→      return {
176→        success: false,
177→        output: capturedOutput,
178→        sessionId: resultSessionId,
179→        error: error + stderrSuffix,
180→        stderrTail: stderrBuffer.getLines(),
181→        stdoutTail: stdoutBuffer.getLines(),
182→      };
183→    }
184→  }
185→
186→  async isAvailable(): Promise<boolean> {
187→    try {
188→      // If we can import the SDK, it's available
189→      await import("@anthropic-ai/claude-agent-sdk");
190→      return true;
191→    } catch {
192→      return false;
193→    }
194→  }
195→}
