 38→      const stdoutBuffer = new RingBuffer(50);
 39→
 40→      const proc = spawn("aider", args, {
 41→        cwd: config.cwd,
 42→        env: { ...process.env, ...config.env },
 43→        stdio: ["ignore", "pipe", "pipe"],
 44→      });
 45→
 46→      // Set up timeout
 47→      const timeoutId = setTimeout(() => {
 48→        proc.kill("SIGTERM");
 49→      }, config.phaseTimeout * 1000);
 50→
 51→      // Wire external abort signal
 52→      if (config.abortSignal) {
 53→        const onAbort = () => {
 54→          proc.kill("SIGTERM");
 55→        };
 56→        config.abortSignal.addEventListener("abort", onAbort);
 57→        proc.on("close", () => {
 58→          config.abortSignal?.removeEventListener("abort", onAbort);
 59→        });
 60→      }
 61→
 62→      proc.stdout.on("data", (data: Buffer) => {
 63→        const text = data.toString();
 64→        capturedOutput += text;
 65→        const lines = text.split("\n").filter((l) => l.length > 0);
 66→        for (const line of lines) {
 67→          stdoutBuffer.push(line);
 68→        }
 69→        if (config.verbose) {
 70→          config.onOutput?.(text);
 71→        }
 72→      });
 73→
 74→      proc.stderr.on("data", (data: Buffer) => {
 75→        const text = data.toString();
 76→        capturedStderr += text;
 77→        const lines = text.split("\n").filter((l) => l.length > 0);
 78→        for (const line of lines) {
 79→          stderrBuffer.push(line);
 80→        }
 81→        config.onStderr?.(text);
 82→      });
 83→
 84→      proc.on("error", (err: NodeJS.ErrnoException) => {
 85→        clearTimeout(timeoutId);
 86→        if (err.code === "ENOENT") {
 87→          resolve({
 88→            success: false,
 89→            output: capturedOutput,
 90→            error:
 91→              "Aider CLI not found. Install it with: pip install aider-chat",
 92→            stderrTail: stderrBuffer.getLines(),
 93→            stdoutTail: stdoutBuffer.getLines(),
 94→          });
 95→        } else {
 96→          resolve({
 97→            success: false,
 98→            output: capturedOutput,
 99→            error: `Failed to start aider: ${err.message}`,
100→            stderrTail: stderrBuffer.getLines(),
101→            stdoutTail: stdoutBuffer.getLines(),
102→          });
103→        }
104→      });
105→
106→      proc.on("close", (code: number | null, signal: string | null) => {
107→        clearTimeout(timeoutId);
108→
109→        if (signal) {
110→          const isTimeout = signal === "SIGTERM";
111→          resolve({
112→            success: false,
113→            output: capturedOutput,
114→            error: isTimeout
115→              ? `Timeout after ${config.phaseTimeout}s`
116→              : `Process killed by signal: ${signal}`,
117→            stderrTail: stderrBuffer.getLines(),
118→            stdoutTail: stdoutBuffer.getLines(),
