135→            success: false,
136→            output: capturedOutput,
137→            error: `Aider exited with code ${code}${stderrSuffix}`,
138→            stderrTail: stderrBuffer.getLines(),
139→            stdoutTail: stdoutBuffer.getLines(),
140→          });
141→        }
142→      });
143→    });
