155→  /** Build the CLI argument list for aider. */
156→  private buildArgs(prompt: string, files?: string[]): string[] {
157→    const args = [
158→      "--yes",
159→      "--no-auto-commits",
160→      "--no-pretty",
161→      "--message",
162→      prompt,
163→    ];
164→
165→    if (this.settings?.model) {
166→      args.push("--model", this.settings.model);
167→    }
168→
169→    if (this.settings?.editFormat) {
170→      args.push("--edit-format", this.settings.editFormat);
171→    }
172→
173→    if (this.settings?.extraArgs) {
174→      args.push(...this.settings.extraArgs);
175→    }
