167→/**
168→ * Execute a single phase for an issue using the configured AgentDriver.
169→ */
170→async function executePhase(
171→  issueNumber: number,
172→  phase: Phase,
173→  config: ExecutionConfig,
174→  sessionId?: string,
175→  worktreePath?: string,
176→  shutdownManager?: ShutdownManager,
177→  spinner?: PhaseSpinner,
178→): Promise<PhaseResult & { sessionId?: string }> {
179→  const startTime = Date.now();
180→
181→  const prompt = await getPhasePrompt(phase, issueNumber, config.agent);
182→
183→  if (config.dryRun) {
184→    // Dry run - show the prompt that would be sent, then return
185→    if (config.verbose) {
186→      console.log(chalk.gray(`    Would execute: /${phase} ${issueNumber}`));
187→      console.log(chalk.gray(`    Prompt: ${prompt}`));
188→    }
189→    return {
190→      phase,
191→      success: true,
192→      durationSeconds: 0,
193→      output: prompt,
194→    };
195→  }
196→
197→  if (config.verbose) {
198→    console.log(chalk.gray(`    Prompt: ${prompt}`));
199→    if (worktreePath && ISOLATED_PHASES.includes(phase)) {
200→      console.log(chalk.gray(`    Worktree: ${worktreePath}`));
201→    }
202→  }
203→
204→  // Determine working directory and environment
205→  const shouldUseWorktree = worktreePath && ISOLATED_PHASES.includes(phase);
206→  const cwd = shouldUseWorktree ? worktreePath : process.cwd();
207→
208→  // Resolve file context for file-oriented drivers (e.g., Aider --file)
209→  let files: string[] | undefined;
210→  if (config.agent && config.agent !== "claude-code") {
211→    try {
212→      const output = execSync("git diff --name-only main...HEAD", {
213→        cwd,
214→        encoding: "utf-8",
215→        stdio: ["pipe", "pipe", "pipe"],
216→      }).trim();
217→      if (output) {
218→        files = output.split("\n").filter(Boolean);
219→      }
220→    } catch {
221→      // No changed files or git error — proceed without file context
222→    }
223→  }
224→
225→  // Check if shutdown is in progress
226→  if (shutdownManager?.shuttingDown) {
227→    return {
228→      phase,
229→      success: false,
230→      durationSeconds: 0,
231→      error: "Shutdown in progress",
232→    };
233→  }
234→
235→  // Create abort controller for timeout
236→  const abortController = new AbortController();
237→  const timeoutId = setTimeout(() => {
238→    abortController.abort();
239→  }, config.phaseTimeout * 1000);
240→
241→  // Register abort controller with shutdown manager for graceful shutdown
242→  // Uses add/remove to support concurrent phase execution (#404)
243→  if (shutdownManager) {
244→    shutdownManager.addAbortController(abortController);
245→  }
246→
247→  // Build environment with worktree isolation variables
248→  const env: Record<string, string> = {
249→    ...process.env,
250→    CLAUDE_HOOKS_SMART_TESTS: config.noSmartTests ? "false" : "true",
251→  };
252→
253→  // Set worktree isolation environment variables
254→  if (shouldUseWorktree) {
255→    env.SEQUANT_WORKTREE = worktreePath;
256→    env.SEQUANT_ISSUE = String(issueNumber);
257→  }
258→
259→  // Set orchestration context for skills to detect they're part of a workflow
260→  // Skills can check these to skip redundant pre-flight checks
261→  env.SEQUANT_ORCHESTRATOR = "sequant-run";
262→  env.SEQUANT_PHASE = phase;
263→
264→  // Track whether we're actively streaming verbose output
265→  // Pausing spinner once per streaming session prevents truncation from rapid pause/resume cycles
266→  // (Issue #283: ora's stop() clears the current line, which can truncate output when
267→  // pause/resume is called for every chunk in rapid succession)
268→  let verboseStreamingActive = false;
269→
270→  // Safety: never resume a session when worktree isolation is active.
271→  // Even if THIS phase doesn't use the worktree, a previous phase may have
272→  // created the session there. Resuming from a different cwd crashes the SDK
273→  // (exit code 1). ISOLATED_PHASES prevents this by design, but this guard
274→  // catches edge cases (e.g. a new phase added without updating ISOLATED_PHASES).
275→  const canResume = sessionId && !worktreePath;
276→
277→  // Build AgentExecutionConfig for the driver
278→  const agentConfig: AgentExecutionConfig = {
279→    cwd,
280→    env,
281→    abortSignal: abortController.signal,
282→    phaseTimeout: config.phaseTimeout,
283→    verbose: config.verbose,
284→    mcp: config.mcp,
285→    sessionId: canResume ? sessionId : undefined,
286→    files,
287→    onOutput: config.verbose
288→      ? (text: string) => {
289→          if (!verboseStreamingActive) {
290→            spinner?.pause();
291→            verboseStreamingActive = true;
292→          }
293→          process.stdout.write(chalk.gray(text));
294→        }
295→      : undefined,
296→    onStderr: config.verbose
297→      ? (data: string) => {
298→          if (!verboseStreamingActive) {
299→            spinner?.pause();
300→            verboseStreamingActive = true;
301→          }
302→          process.stderr.write(chalk.red(data));
303→        }
304→      : undefined,
305→  };
306→
307→  // Resolve driver from config or default
308→  const driver: AgentDriver = getDriver(config.agent, {
309→    aiderSettings: config.aiderSettings,
310→  });
311→
312→  const agentResult = await driver.executePhase(prompt, agentConfig);
313→
314→  // Resume spinner after execution completes (if we paused it)
315→  if (verboseStreamingActive) {
316→    spinner?.resume();
317→  }
318→
319→  clearTimeout(timeoutId);
320→
321→  // Remove this specific abort controller from shutdown manager
322→  if (shutdownManager) {
323→    shutdownManager.removeAbortController(abortController);
324→  }
325→
326→  const durationSeconds = (Date.now() - startTime) / 1000;
327→
328→  // Map AgentPhaseResult to PhaseResult
329→  const tails = {
330→    stderrTail: agentResult.stderrTail,
331→    stdoutTail: agentResult.stdoutTail,
332→  };
333→
334→  if (agentResult.success) {
335→    // For QA phase, check the verdict to determine actual success
336→    // Agent "success" just means the execution completed — we need to parse the verdict
337→    if (phase === "qa" && agentResult.output) {
338→      const verdict = parseQaVerdict(agentResult.output);
339→      if (
340→        verdict &&
341→        verdict !== "READY_FOR_MERGE" &&
342→        verdict !== "NEEDS_VERIFICATION"
343→      ) {
344→        return {
345→          phase,
346→          success: false,
347→          durationSeconds,
348→          error: `QA verdict: ${verdict}`,
349→          sessionId: agentResult.sessionId,
350→          output: agentResult.output,
351→          verdict,
352→          ...tails,
353→        };
354→      }
355→      return {
356→        phase,
357→        success: true,
358→        durationSeconds,
359→        sessionId: agentResult.sessionId,
360→        output: agentResult.output,
361→        verdict: verdict ?? undefined,
362→        ...tails,
363→      };
364→    }
365→
366→    return {
367→      phase,
368→      success: true,
369→      durationSeconds,
370→      sessionId: agentResult.sessionId,
371→      output: agentResult.output,
372→      ...tails,
373→    };
374→  }
375→
376→  return {
377→    phase,
378→    success: false,
379→    durationSeconds,
380→    error: agentResult.error,
381→    sessionId: agentResult.sessionId,
382→    ...tails,
383→  };
384→}
