  37→/**
  38→ * Emit a structured progress line to stderr for MCP progress notifications.
  39→ * Only emits when running under an orchestrator (e.g., MCP server).
  40→ * The MCP handler parses these lines to send `notifications/progress`.
  41→ *
  42→ * @param issue - GitHub issue number
  43→ * @param phase - Phase name (e.g., "spec", "exec", "qa")
  44→ * @param event - Phase lifecycle event: "start", "complete", or "failed"
  45→ * @param extra - Optional fields: durationSeconds (on complete), error (on failed)
  46→ */
  47→export function emitProgressLine(
  48→  issue: number,
  49→  phase: string,
  50→  event: "start" | "complete" | "failed" = "start",
  51→  extra?: { durationSeconds?: number; error?: string },
  52→): void {
  53→  if (!process.env.SEQUANT_ORCHESTRATOR) return;
  54→  const payload: Record<string, unknown> = { issue, phase, event };
  55→  if (extra?.durationSeconds !== undefined) {
  56→    payload.durationSeconds = extra.durationSeconds;
  57→  }
  58→  if (extra?.error !== undefined) {
  59→    payload.error = extra.error;
  60→  }
  61→  const line = `SEQUANT_PROGRESS:${JSON.stringify(payload)}\n`;
  62→  process.stderr.write(line);
  63→}
