  86→  quiet?: boolean;
  87→  /** Chain issues: each branches from previous (requires --sequential) */
  88→  chain?: boolean;
  89→  /**
  90→   * Wait for QA pass before starting next issue in chain mode.
  91→   * When enabled, the chain pauses if QA fails, preventing downstream issues
  92→   * from building on potentially broken code.
  93→   */
  94→  qaGate?: boolean;
  95→  /**
  96→   * Base branch for worktree creation.
  97→   * Resolution priority: this CLI flag → settings.run.defaultBase → 'main'
  98→   */
  99→  base?: string;
 100→  /**
 101→   * Disable MCP servers in headless mode.
 102→   * When true, MCPs are not passed to the SDK (faster/cheaper runs).
 103→   * Resolution priority: this CLI flag → settings.run.mcp → default (true)
 104→   */
 105→  noMcp?: boolean;
 106→  /**
 107→   * Resume from last completed phase.
 108→   * Reads phase markers from GitHub issue comments and skips completed phases.
 109→   */
 110→  resume?: boolean;
 111→  /**
 112→   * Disable automatic retry with MCP fallback.
 113→   * When true, no retry attempts are made on phase failure.
 114→   * Useful for debugging to see the actual failure without retry masking it.
 115→   */
 116→  noRetry?: boolean;
 117→  /**
 118→   * Skip pre-PR rebase onto the base branch.
 119→   * When true, branches are not rebased before creating the PR.
 120→   * Use when you want to preserve branch state or handle rebasing manually.
 121→   */
 122→  noRebase?: boolean;
 123→  /**
 124→   * Skip PR creation after successful QA.
 125→   * When true, branches are pushed but no PR is created.
 126→   * Useful for manual workflows where PRs are created separately.
 127→   */
 128→  noPr?: boolean;
 129→  /**
 130→   * Force re-execution of issues even if they have completed status.
 131→   * Bypasses the pre-flight state guard that skips ready_for_merge/merged issues.
 132→   */
 133→  force?: boolean;
 134→  /**
 135→   * Analyze run results and suggest workflow improvements.
 136→   * Displays observations about timing patterns, phase mismatches, and
 137→   * actionable suggestions after the summary output.
 138→   */
 139→  reflect?: boolean;
 140→  /**
 141→   * Max concurrent issues in parallel mode (default: 3).
 142→   * Only applies when --sequential is not set.
 143→   */
 144→  concurrency?: number;
 145→  /**
 146→   * Agent driver for phase execution.
 147→   * Default: "claude-code"
 148→   */
 149→  agent?: string;
 150→}
