 157→      "gh",
 158→      ["issue", "view", String(issueNumber), "--json", "title,labels"],
 159→      { stdio: "pipe" },
 160→    );
 161→
 162→    if (result.status === 0) {
 163→      const data = JSON.parse(result.stdout.toString());
 164→      return {
 165→        title: data.title || `Issue #${issueNumber}`,
 166→        labels: Array.isArray(data.labels)
 167→          ? data.labels.map((l: { name: string }) => l.name)
 168→          : [],
 169→      };
 170→    }
 171→  } catch {
 172→    // Ignore errors, use defaults
 173→  }
 174→
 175→  return { title: `Issue #${issueNumber}`, labels: [] };
 176→}
