 178→/**
 179→ * Parse dependencies from issue body and labels
 180→ * Returns array of issue numbers this issue depends on
 181→ */
 182→export function parseDependencies(issueNumber: number): number[] {
 183→  try {
 184→    const result = spawnSync(
 185→      "gh",
 186→      ["issue", "view", String(issueNumber), "--json", "body,labels"],
 187→      { stdio: "pipe" },
 188→    );
 189→
 190→    if (result.status !== 0) return [];
 191→
 192→    const data = JSON.parse(result.stdout.toString());
 193→    const dependencies: number[] = [];
 194→
 195→    // Parse from body: "Depends on: #123" or "**Depends on**: #123"
 196→    if (data.body) {
 197→      const bodyMatch = data.body.match(
 198→        /\*?\*?depends\s+on\*?\*?:?\s*#?(\d+)/gi,
 199→      );
 200→      if (bodyMatch) {
 201→        for (const match of bodyMatch) {
 202→          const numMatch = match.match(/(\d+)/);
 203→          if (numMatch) {
 204→            dependencies.push(parseInt(numMatch[1], 10));
 205→          }
 206→        }
 207→      }
 208→    }
 209→
 210→    // Parse from labels: "depends-on/123" or "depends-on-123"
 211→    if (data.labels && Array.isArray(data.labels)) {
 212→      for (const label of data.labels) {
 213→        const labelName = label.name || label;
 214→        const labelMatch = labelName.match(/depends-on[-/](\d+)/i);
 215→        if (labelMatch) {
 216→          dependencies.push(parseInt(labelMatch[1], 10));
 217→        }
 218→      }
 219→    }
 220→
 221→    return [...new Set(dependencies)]; // Remove duplicates
 222→  } catch {
 223→    return [];
 224→  }
 225→}
 226→
 227→/**
 228→ * Sort issues by dependencies (topological sort)
 229→ * Issues with no dependencies come first, then issues that depend on them
 230→ */
 231→export function sortByDependencies(issueNumbers: number[]): number[] {
 232→  // Build dependency graph
 233→  const dependsOn = new Map<number, number[]>();
 234→  for (const issue of issueNumbers) {
 235→    const deps = parseDependencies(issue);
 236→    // Only include dependencies that are in our issue list
 237→    dependsOn.set(
 238→      issue,
 239→      deps.filter((d) => issueNumbers.includes(d)),
 240→    );
 241→  }
 242→
 243→  // Topological sort using Kahn's algorithm
 244→  const inDegree = new Map<number, number>();
 245→  for (const issue of issueNumbers) {
 246→    inDegree.set(issue, 0);
 247→  }
 248→  for (const deps of dependsOn.values()) {
 249→    for (const dep of deps) {
 250→      inDegree.set(dep, (inDegree.get(dep) || 0) + 1);
 251→    }
 252→  }
 253→
 254→  // Note: inDegree counts how many issues depend on each issue
 255→  // We want to process issues that have no dependencies first,
 256→  // so dependent issues come after their prerequisites
 257→  const sorted: number[] = [];
 258→  const queue: number[] = [];
 259→
 260→  // Start with issues that have no dependencies
 261→  for (const issue of issueNumbers) {
 262→    const deps = dependsOn.get(issue) || [];
 263→    if (deps.length === 0) {
 264→      queue.push(issue);
 265→    }
 266→  }
 267→
 268→  const visited = new Set<number>();
 269→  while (queue.length > 0) {
 270→    const issue = queue.shift()!;
 271→    if (visited.has(issue)) continue;
 272→    visited.add(issue);
 273→    sorted.push(issue);
 274→
 275→    // Find issues that depend on this one
 276→    for (const [other, deps] of dependsOn.entries()) {
 277→      if (deps.includes(issue) && !visited.has(other)) {
 278→        // Check if all dependencies of 'other' are satisfied
 279→        const allDepsSatisfied = deps.every((d) => visited.has(d));
 280→        if (allDepsSatisfied) {
 281→          queue.push(other);
 282→        }
 283→      }
 284→    }
 285→  }
 286→
 287→  // Add any remaining issues (circular dependencies or unvisited)
 288→  for (const issue of issueNumbers) {
 289→    if (!visited.has(issue)) {
 290→      sorted.push(issue);
 291→    }
 292→  }
 293→
 294→  return sorted;
 295→}
