 309→/**
 310→ * Parse environment variables for CI configuration
 311→ */
 312→export function getEnvConfig(): Partial<RunOptions> {
 313→  const config: Partial<RunOptions> = {};
 314→
 315→  if (process.env.SEQUANT_QUALITY_LOOP === "true") {
 316→    config.qualityLoop = true;
 317→  }
 318→
 319→  if (process.env.SEQUANT_MAX_ITERATIONS) {
 320→    const maxIter = parseInt(process.env.SEQUANT_MAX_ITERATIONS, 10);
 321→    if (!isNaN(maxIter)) {
 322→      config.maxIterations = maxIter;
 323→    }
 324→  }
 325→
 326→  if (process.env.SEQUANT_SMART_TESTS === "false") {
 327→    config.noSmartTests = true;
 328→  }
 329→
 330→  if (process.env.SEQUANT_TESTGEN === "true") {
 331→    config.testgen = true;
 332→  }
 333→
 334→  return config;
 335→}
