 337→export async function executeBatch(
 338→  issueNumbers: number[],
 339→  config: ExecutionConfig,
 340→  logWriter: LogWriter | null,
 341→  stateManager: StateManager | null,
 342→  options: RunOptions,
 343→  issueInfoMap: Map<number, { title: string; labels: string[] }>,
 344→  worktreeMap: Map<number, WorktreeInfo>,
 345→  shutdownManager?: ShutdownManager,
 346→  packageManager?: string,
 347→  baseBranch?: string,
 348→): Promise<IssueResult[]> {
 349→  const results: IssueResult[] = [];
 350→
 351→  for (const issueNumber of issueNumbers) {
 352→    // Check if shutdown was triggered
 353→    if (shutdownManager?.shuttingDown) {
 354→      break;
 355→    }
 356→
 357→    const issueInfo = issueInfoMap.get(issueNumber) ?? {
 358→      title: `Issue #${issueNumber}`,
 359→      labels: [],
 360→    };
 361→    const worktreeInfo = worktreeMap.get(issueNumber);
 362→
 363→    // Start issue logging
 364→    if (logWriter) {
 365→      logWriter.startIssue(issueNumber, issueInfo.title, issueInfo.labels);
 366→    }
 367→
 368→    const result = await runIssueWithLogging(
 369→      issueNumber,
 370→      config,
 371→      logWriter,
 372→      stateManager,
 373→      issueInfo.title,
 374→      issueInfo.labels,
 375→      options,
 376→      worktreeInfo?.path,
 377→      worktreeInfo?.branch,
 378→      shutdownManager,
 379→      false, // Batch mode doesn't support chain
 380→      packageManager,
 381→      undefined,
 382→      baseBranch,
 383→    );
 384→    results.push(result);
 385→
 386→    // Record PR info in log before completing issue
 387→    if (logWriter && result.prNumber && result.prUrl) {
 388→      logWriter.setPRInfo(result.prNumber, result.prUrl);
 389→    }
 390→
 391→    // Complete issue logging
 392→    if (logWriter) {
 393→      logWriter.completeIssue();
 394→    }
 395→  }
 396→
 397→  return results;
 398→}
 399→
 400→export async function runIssueWithLogging(
 401→  issueNumber: number,
 402→  config: ExecutionConfig,
 403→  logWriter: LogWriter | null,
 404→  stateManager: StateManager | null,
 405→  issueTitle: string,
 406→  labels: string[],
 407→  options: RunOptions,
 408→  worktreePath?: string,
 409→  branch?: string,
 410→  shutdownManager?: ShutdownManager,
 411→  chainMode?: boolean,
 412→  packageManager?: string,
 413→  isLastInChain?: boolean,
 414→  baseBranch?: string,
 415→): Promise<IssueResult> {
 416→  const startTime = Date.now();
 417→  const phaseResults: PhaseResult[] = [];
 418→  let loopTriggered = false;
 419→  let sessionId: string | undefined;
 420→
 421→  // In parallel mode, suppress per-issue terminal output to prevent interleaving.
 422→  // The caller (run.ts) handles progress display via updateProgress().
 423→  const log = config.parallel ? () => {} : console.log.bind(console);
 424→
 425→  log(chalk.blue(`\n  Issue #${issueNumber}`));
 426→  if (worktreePath) {
 427→    log(chalk.gray(`    Worktree: ${worktreePath}`));
 428→  }
 429→
 430→  // Initialize state tracking for this issue
 431→  if (stateManager) {
 432→    try {
 433→      const existingState = await stateManager.getIssueState(issueNumber);
 434→      if (!existingState) {
 435→        await stateManager.initializeIssue(issueNumber, issueTitle, {
 436→          worktree: worktreePath,
 437→          branch,
 438→          qualityLoop: config.qualityLoop,
 439→          maxIterations: config.maxIterations,
 440→        });
 441→      } else {
 442→        // Update worktree info if it changed
 443→        if (worktreePath && branch) {
 444→          await stateManager.updateWorktreeInfo(
 445→            issueNumber,
 446→            worktreePath,
 447→            branch,
 448→          );
 449→        }
 450→      }
 451→    } catch (error) {
 452→      // State tracking errors shouldn't stop execution
 453→      if (config.verbose) {
 454→        log(chalk.yellow(`    ⚠️  State tracking error: ${error}`));
 455→      }
 456→    }
 457→  }
 458→
 459→  // Determine phases for this specific issue
 460→  let phases: Phase[];
 461→  let detectedQualityLoop = false;
 462→  let specAlreadyRan = false;
 463→
 464→  if (options.autoDetectPhases) {
 465→    // Check if labels indicate a simple bug/fix (skip spec entirely)
 466→    const lowerLabels = labels.map((l) => l.toLowerCase());
 467→    const isSimpleBugFix = lowerLabels.some((label) =>
 468→      BUG_LABELS.some((bugLabel) => label.includes(bugLabel)),
 469→    );
 470→
 471→    if (isSimpleBugFix) {
 472→      // Simple bug fix: skip spec, go straight to exec → qa
 473→      phases = ["exec", "qa"];
 474→      log(chalk.gray(`    Bug fix detected: ${phases.join(" → ")}`));
 475→    } else {
 476→      // Run spec first to get recommended workflow
 477→      log(chalk.gray(`    Running spec to determine workflow...`));
 478→
 479→      // Create spinner for spec phase (suppressed in parallel mode to prevent interleaving)
 480→      const specSpinner = config.parallel
 481→        ? undefined
 482→        : new PhaseSpinner({
 483→            phase: "spec",
 484→            phaseIndex: 1,
 485→            totalPhases: 3, // Estimate; will be refined after spec
 486→            shutdownManager,
 487→          });
 488→      specSpinner?.start();
 489→      emitProgressLine(issueNumber, "spec", "start");
 490→
 491→      // Track spec phase start in state
 492→      if (stateManager) {
 493→        try {
 494→          await stateManager.updatePhaseStatus(
 495→            issueNumber,
 496→            "spec",
 497→            "in_progress",
 498→          );
 499→        } catch {
 500→          // State tracking errors shouldn't stop execution
 501→        }
 502→      }
 503→
 504→      const specStartTime = new Date();
 505→      // Note: spec runs in main repo (not worktree) for planning
 506→      const specResult = await executePhaseWithRetry(
 507→        issueNumber,
 508→        "spec",
 509→        config,
 510→        sessionId,
 511→        worktreePath, // Will be ignored for spec (non-isolated phase)
 512→        shutdownManager,
 513→        specSpinner,
 514→      );
 515→      const specEndTime = new Date();
 516→
 517→      if (specResult.sessionId) {
 518→        sessionId = specResult.sessionId;
 519→        // Update session ID in state for resume capability
 520→        if (stateManager) {
 521→          try {
 522→            await stateManager.updateSessionId(
 523→              issueNumber,
 524→              specResult.sessionId,
 525→            );
 526→          } catch {
 527→            // State tracking errors shouldn't stop execution
 528→          }
 529→        }
 530→      }
 531→
 532→      phaseResults.push(specResult);
 533→      specAlreadyRan = true;
 534→
 535→      // Emit completion/failure progress event (AC-8)
 536→      const specDurationSec = Math.round(
 537→        (specEndTime.getTime() - specStartTime.getTime()) / 1000,
 538→      );
 539→      if (specResult.success) {
 540→        emitProgressLine(issueNumber, "spec", "complete", {
 541→          durationSeconds: specDurationSec,
 542→        });
 543→      } else {
 544→        emitProgressLine(issueNumber, "spec", "failed", {
 545→          error: specResult.error ?? "unknown",
 546→        });
 547→      }
 548→
 549→      // Log spec phase result
 550→      // Note: Spec runs in main repo, not worktree, so no git diff stats
 551→      if (logWriter) {
 552→        // Build errorContext from captured stderr/stdout tails (#447)
 553→        let specErrorContext: ErrorContext | undefined;
 554→        if (!specResult.success && specResult.stderrTail) {
 555→          specErrorContext = {
 556→            stderrTail: specResult.stderrTail ?? [],
 557→            stdoutTail: specResult.stdoutTail ?? [],
 558→            category: classifyError(specResult.stderrTail ?? []),
 559→          };
 560→        }
 561→        const phaseLog = createPhaseLogFromTiming(
 562→          "spec",
 563→          issueNumber,
 564→          specStartTime,
 565→          specEndTime,
 566→          specResult.success
 567→            ? "success"
 568→            : specResult.error?.includes("Timeout")
 569→              ? "timeout"
 570→              : "failure",
 571→          { error: specResult.error, errorContext: specErrorContext },
 572→        );
 573→        logWriter.logPhase(phaseLog);
 574→      }
 575→
 576→      // Track spec phase completion in state
 577→      if (stateManager) {
 578→        try {
 579→          const phaseStatus = specResult.success ? "completed" : "failed";
 580→          await stateManager.updatePhaseStatus(
 581→            issueNumber,
 582→            "spec",
 583→            phaseStatus,
 584→            {
 585→              error: specResult.error,
 586→            },
 587→          );
 588→        } catch {
 589→          // State tracking errors shouldn't stop execution
 590→        }
 591→      }
 592→
 593→      if (!specResult.success) {
 594→        specSpinner?.fail(specResult.error);
 595→        const durationSeconds = (Date.now() - startTime) / 1000;
 596→        return {
 597→          issueNumber,
 598→          success: false,
 599→          phaseResults,
 600→          durationSeconds,
 601→          loopTriggered: false,
 602→        };
 603→      }
 604→
 605→      specSpinner?.succeed();
 606→
 607→      // Parse recommended workflow from spec output
 608→      const parsedWorkflow = specResult.output
 609→        ? parseRecommendedWorkflow(specResult.output)
 610→        : null;
 611→
 612→      if (parsedWorkflow) {
 613→        // Remove spec from phases since we already ran it
 614→        phases = parsedWorkflow.phases.filter((p) => p !== "spec");
 615→        detectedQualityLoop = parsedWorkflow.qualityLoop;
 616→        log(
 617→          chalk.gray(
 618→            `    Spec recommends: ${phases.join(" → ")}${detectedQualityLoop ? " (quality loop)" : ""}`,
 619→          ),
 620→        );
 621→      } else {
 622→        // Fall back to label-based detection
 623→        log(
 624→          chalk.yellow(
 625→            `    Could not parse spec recommendation, using label-based detection`,
 626→          ),
 627→        );
 628→        const detected = detectPhasesFromLabels(labels);
 629→        phases = detected.phases.filter((p) => p !== "spec");
 630→        detectedQualityLoop = detected.qualityLoop;
 631→        log(chalk.gray(`    Fallback: ${phases.join(" → ")}`));
 632→      }
 633→    }
 634→  } else {
 635→    // Use explicit phases with adjustments
 636→    phases = determinePhasesForIssue(config.phases, labels, options);
 637→    if (phases.length !== config.phases.length) {
 638→      log(chalk.gray(`    Phases adjusted: ${phases.join(" → ")}`));
 639→    }
 640→  }
 641→
 642→  // Resume: filter out completed phases if --resume flag is set
 643→  if (options.resume) {
 644→    const resumeResult = filterResumedPhases(issueNumber, phases, true);
 645→    if (resumeResult.skipped.length > 0) {
 646→      log(
 647→        chalk.gray(
 648→          `    Resume: skipping completed phases: ${resumeResult.skipped.join(", ")}`,
 649→        ),
 650→      );
 651→      phases = resumeResult.phases;
 652→    }
 653→    // Also skip spec if it was auto-detected as completed
 654→    if (
 655→      specAlreadyRan &&
 656→      resumeResult.skipped.length === 0 &&
 657→      resumeResult.phases.length === 0
 658→    ) {
 659→      log(chalk.gray(`    Resume: all phases already completed`));
 660→    }
 661→  }
 662→
 663→  // Add testgen phase if requested (and spec was in the phases)
 664→  if (
 665→    options.testgen &&
 666→    (phases.includes("spec") || specAlreadyRan) &&
 667→    !phases.includes("testgen")
 668→  ) {
 669→    // Insert testgen at the beginning if spec already ran, otherwise after spec
 670→    if (specAlreadyRan) {
 671→      phases.unshift("testgen");
 672→    } else {
 673→      const specIndex = phases.indexOf("spec");
 674→      if (specIndex !== -1) {
 675→        phases.splice(specIndex + 1, 0, "testgen");
 676→      }
 677→    }
 678→  }
 679→
 680→  let iteration = 0;
 681→  const useQualityLoop = config.qualityLoop || detectedQualityLoop;
 682→  const maxIterations = useQualityLoop ? config.maxIterations : 1;
 683→  let completedSuccessfully = false;
 684→
 685→  while (iteration < maxIterations) {
 686→    iteration++;
 687→
 688→    if (useQualityLoop && iteration > 1) {
 689→      log(
 690→        chalk.yellow(
 691→          `    Quality loop iteration ${iteration}/${maxIterations}`,
 692→        ),
 693→      );
 694→      loopTriggered = true;
 695→    }
 696→
 697→    let phasesFailed = false;
 698→
 699→    // Calculate total phases for progress indicator
 700→    // If spec already ran in auto-detect mode, it's counted separately
 701→    const totalPhases = specAlreadyRan ? phases.length + 1 : phases.length;
 702→    const phaseIndexOffset = specAlreadyRan ? 1 : 0;
 703→
 704→    for (let phaseIdx = 0; phaseIdx < phases.length; phaseIdx++) {
 705→      const phase = phases[phaseIdx];
 706→      const phaseNumber = phaseIdx + 1 + phaseIndexOffset;
 707→
 708→      // Create spinner for this phase (suppressed in parallel mode)
 709→      const phaseSpinner = config.parallel
 710→        ? undefined
 711→        : new PhaseSpinner({
 712→            phase,
 713→            phaseIndex: phaseNumber,
 714→            totalPhases,
 715→            shutdownManager,
 716→            iteration: useQualityLoop ? iteration : undefined,
 717→          });
 718→      phaseSpinner?.start();
 719→      emitProgressLine(issueNumber, phase, "start");
 720→
 721→      // Track phase start in state
 722→      if (stateManager) {
 723→        try {
 724→          await stateManager.updatePhaseStatus(
 725→            issueNumber,
 726→            phase as Phase,
 727→            "in_progress",
 728→          );
 729→        } catch {
 730→          // State tracking errors shouldn't stop execution
 731→        }
 732→      }
 733→
 734→      const phaseStartTime = new Date();
 735→      const result = await executePhaseWithRetry(
 736→        issueNumber,
 737→        phase,
 738→        config,
 739→        sessionId,
 740→        worktreePath,
 741→        shutdownManager,
 742→        phaseSpinner,
 743→      );
 744→      const phaseEndTime = new Date();
 745→
 746→      // Capture session ID for subsequent phases
 747→      if (result.sessionId) {
 748→        sessionId = result.sessionId;
 749→        // Update session ID in state for resume capability
 750→        if (stateManager) {
 751→          try {
 752→            await stateManager.updateSessionId(issueNumber, result.sessionId);
 753→          } catch {
 754→            // State tracking errors shouldn't stop execution
 755→          }
 756→        }
 757→      }
 758→
 759→      phaseResults.push(result);
 760→
 761→      // Emit completion/failure progress event (AC-8)
 762→      const phaseDurationSec = Math.round(
 763→        (phaseEndTime.getTime() - phaseStartTime.getTime()) / 1000,
 764→      );
 765→      if (result.success) {
 766→        emitProgressLine(issueNumber, phase, "complete", {
 767→          durationSeconds: phaseDurationSec,
 768→        });
 769→      } else {
 770→        emitProgressLine(issueNumber, phase, "failed", {
 771→          error: result.error ?? "unknown",
 772→        });
 773→      }
 774→
 775→      // Log phase result with observability data (AC-1, AC-2, AC-3, AC-7)
 776→      if (logWriter) {
 777→        // Capture git diff stats for worktree phases (AC-1, AC-3)
 778→        const diffStats = worktreePath
 779→          ? getGitDiffStats(worktreePath, baseBranch)
 780→          : undefined;
 781→
 782→        // Capture commit hash after phase (AC-2)
 783→        const commitHash = worktreePath
 784→          ? getCommitHash(worktreePath)
 785→          : undefined;
 786→
 787→        // Read cache metrics for QA phase (AC-7)
 788→        const cacheMetrics =
 789→          phase === "qa" ? readCacheMetrics(worktreePath) : undefined;
 790→
 791→        // Build errorContext from captured stderr/stdout tails (#447)
 792→        let errorContext: ErrorContext | undefined;
 793→        if (!result.success && result.stderrTail) {
 794→          errorContext = {
 795→            stderrTail: result.stderrTail ?? [],
 796→            stdoutTail: result.stdoutTail ?? [],
 797→            category: classifyError(result.stderrTail ?? []),
 798→          };
 799→        }
 800→
 801→        const phaseLog = createPhaseLogFromTiming(
 802→          phase,
 803→          issueNumber,
 804→          phaseStartTime,
 805→          phaseEndTime,
 806→          result.success
 807→            ? "success"
 808→            : result.error?.includes("Timeout")
 809→              ? "timeout"
 810→              : "failure",
 811→          {
 812→            error: result.error,
 813→            verdict: result.verdict,
 814→            // Observability fields (AC-1, AC-2, AC-3, AC-7)
 815→            filesModified: diffStats?.filesModified,
 816→            fileDiffStats: diffStats?.fileDiffStats,
 817→            commitHash,
 818→            cacheMetrics,
 819→            errorContext,
 820→          },
 821→        );
 822→        logWriter.logPhase(phaseLog);
 823→      }
 824→
 825→      // Track phase completion in state
 826→      if (stateManager) {
 827→        try {
 828→          const phaseStatus = result.success
 829→            ? "completed"
 830→            : result.error?.includes("Timeout")
 831→              ? "failed"
 832→              : "failed";
 833→          await stateManager.updatePhaseStatus(
 834→            issueNumber,
 835→            phase as Phase,
 836→            phaseStatus,
 837→            { error: result.error },
 838→          );
 839→        } catch {
 840→          // State tracking errors shouldn't stop execution
 841→        }
 842→      }
 843→
 844→      if (result.success) {
 845→        phaseSpinner?.succeed();
 846→      } else {
 847→        phaseSpinner?.fail(result.error);
 848→        phasesFailed = true;
 849→
 850→        // If quality loop enabled, run loop phase to fix issues
 851→        if (useQualityLoop && iteration < maxIterations) {
 852→          // Create spinner for loop phase (suppressed in parallel mode)
 853→          const loopSpinner = config.parallel
 854→            ? undefined
 855→            : new PhaseSpinner({
 856→                phase: "loop",
 857→                phaseIndex: phaseNumber,
 858→                totalPhases,
 859→                shutdownManager,
 860→                iteration,
 861→              });
 862→          loopSpinner?.start();
 863→          emitProgressLine(issueNumber, "loop", "start");
 864→
 865→          const loopStartTime = new Date();
 866→          const loopResult = await executePhaseWithRetry(
 867→            issueNumber,
 868→            "loop",
 869→            config,
 870→            sessionId,
 871→            worktreePath,
 872→            shutdownManager,
 873→            loopSpinner,
 874→          );
 875→          const loopEndTime = new Date();
 876→          phaseResults.push(loopResult);
 877→
 878→          // Emit loop completion/failure progress event (AC-8)
 879→          const loopDurationSec = Math.round(
 880→            (loopEndTime.getTime() - loopStartTime.getTime()) / 1000,
 881→          );
 882→          if (loopResult.success) {
 883→            emitProgressLine(issueNumber, "loop", "complete", {
 884→              durationSeconds: loopDurationSec,
 885→            });
 886→          } else {
 887→            emitProgressLine(issueNumber, "loop", "failed", {
 888→              error: loopResult.error ?? "unknown",
 889→            });
 890→          }
 891→
 892→          if (loopResult.sessionId) {
 893→            sessionId = loopResult.sessionId;
 894→          }
 895→
 896→          if (loopResult.success) {
 897→            loopSpinner?.succeed();
 898→            // Continue to next iteration
 899→            break;
 900→          } else {
 901→            loopSpinner?.fail(loopResult.error);
 902→          }
 903→        }
 904→
 905→        // Stop on first failure (if not in quality loop or loop failed)
 906→        break;
 907→      }
 908→    }
 909→
 910→    // If all phases passed, exit the loop
 911→    if (!phasesFailed) {
 912→      completedSuccessfully = true;
 913→      break;
 914→    }
 915→
 916→    // If we're not in quality loop mode, don't retry
 917→    if (!config.qualityLoop) {
 918→      break;
 919→    }
 920→  }
 921→
 922→  const durationSeconds = (Date.now() - startTime) / 1000;
 923→  // Success is determined by whether all phases completed in any iteration,
 924→  // not whether all accumulated phase results passed (which would fail after loop recovery)
 925→  const success = completedSuccessfully;
 926→
 927→  // Update final issue status in state
 928→  if (stateManager) {
 929→    try {
 930→      const finalStatus = success ? "ready_for_merge" : "in_progress";
 931→      await stateManager.updateIssueStatus(issueNumber, finalStatus);
 932→    } catch {
 933→      // State tracking errors shouldn't stop execution
 934→    }
 935→  }
 936→
 937→  // Create checkpoint commit in chain mode after QA passes
 938→  if (success && chainMode && worktreePath) {
 939→    createCheckpointCommit(worktreePath, issueNumber, config.verbose);
 940→  }
 941→
 942→  // Rebase onto the base branch before PR creation (unless --no-rebase)
 943→  // This ensures the branch is up-to-date and prevents lockfile drift
 944→  // AC-1: Non-chain mode rebases onto the base branch before PR
 945→  // AC-2: Chain mode rebases only the final branch onto the base branch before PR
 946→  //        (intermediate branches must stay based on their predecessor)
 947→  const shouldRebase =
 948→    success &&
 949→    worktreePath &&
 950→    !options.noRebase &&
 951→    (!chainMode || isLastInChain);
 952→  if (shouldRebase) {
 953→    rebaseBeforePR(
 954→      worktreePath,
 955→      issueNumber,
 956→      packageManager,
 957→      config.verbose,
 958→      baseBranch,
 959→    );
 960→  }
 961→
 962→  // Create PR after successful QA + rebase (unless --no-pr)
 963→  let prNumber: number | undefined;
 964→  let prUrl: string | undefined;
 965→  const shouldCreatePR = success && worktreePath && branch && !options.noPr;
 966→  if (shouldCreatePR) {
 967→    const prResult = createPR(
 968→      worktreePath,
 969→      issueNumber,
 970→      issueTitle,
 971→      branch,
 972→      config.verbose,
 973→      labels,
 974→    );
 975→    if (prResult.success && prResult.prNumber && prResult.prUrl) {
 976→      prNumber = prResult.prNumber;
 977→      prUrl = prResult.prUrl;
 978→
 979→      // Update workflow state with PR info
 980→      if (stateManager) {
 981→        try {
 982→          await stateManager.updatePRInfo(issueNumber, {
 983→            number: prResult.prNumber,
 984→            url: prResult.prUrl,
 985→          });
 986→        } catch {
 987→          // State tracking errors shouldn't stop execution
 988→        }
 989→      }
 990→    }
 991→  }
 992→
 993→  return {
 994→    issueNumber,
 995→    success,
 996→    phaseResults,
 997→    durationSeconds,
 998→    loopTriggered,
 999→    prNumber,
1000→    prUrl,
1001→  };
1002→}
