 18→describe("RingBuffer", () => {
 19→  describe("AC-1: Output tail capture", () => {
 20→    it("should retain last 50 lines when more than 50 lines are pushed", () => {
 21→      const buffer = new RingBuffer(50);
 22→      for (let i = 0; i < 100; i++) {
 23→        buffer.push(`line-${i}`);
 24→      }
 25→
 26→      const lines = buffer.getLines();
 27→      expect(lines).toHaveLength(50);
