 1→/**
 2→ * RingBuffer — fixed-capacity circular buffer for retaining the last N lines.
 3→ *
 4→ * Used by agent drivers to capture the tail of stderr/stdout without
 5→ * unbounded memory growth.
 6→ */
 7→
 8→export class RingBuffer {
 9→  private buffer: string[];
10→  private head = 0;
11→  private count = 0;
12→  private readonly capacity: number;
13→
14→  constructor(capacity: number) {
15→    this.capacity = capacity;
16→    this.buffer = new Array<string>(capacity);
17→  }
18→
19→  /** Push a line into the buffer, evicting the oldest if at capacity. */
20→  push(line: string): void {
21→    this.buffer[this.head] = line;
22→    this.head = (this.head + 1) % this.capacity;
23→    if (this.count < this.capacity) {
24→      this.count++;
25→    }
26→  }
27→
28→  /** Return the stored lines in insertion order (oldest first). */
29→  getLines(): string[] {
30→    if (this.count === 0) return [];
31→    if (this.count < this.capacity) {
32→      return this.buffer.slice(0, this.count);
33→    }
34→    // Buffer is full — head points to the oldest entry
35→    return [
36→      ...this.buffer.slice(this.head),
37→      ...this.buffer.slice(0, this.head),
38→    ];
39→  }
40→}
