      // for stats consumption
      const phaseLogs = [
        {
          phase: "exec",
          issueNumber: 1,
          startTime: "2026-01-01T00:00:00.000Z",
          endTime: "2026-01-01T00:05:00.000Z",
          durationSeconds: 300,
          status: "failure",
          error: "exit 1",
          errorContext: {
            stderrTail: ["context window exceeded"],
            stdoutTail: [],
